{ Launch Interceptor Program decision core (Knight & Leveson, 1986).
  Standalone program: reads one JSON object from stdin, writes one JSON object to stdout.
  REALCOMPARE matches realcompare_reference.pas verbatim. }

program lipdecide;

{$mode objfpc}{$H+}

uses
  SysUtils, Math, Classes;

const
  PI = 3.1415926535;

type
  POINTRANGE = 1..100;
  LICRANGE = 1..15;
  NPOINTS = 2..100;
  NPTYPE = 3..100;
  CONNECTORS = (NOTUSED, ORR, ANDD);
  NUMQUADS = 1..3;
  COORDINATE = array[POINTRANGE] of double;
  CMATRIX = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX = array[LICRANGE, LICRANGE] of Boolean;
  VECTOR = array[LICRANGE] of Boolean;
  COMPTYPE = (LT, EQ, GT);
  TJLex = record
    t: string;
    p: Integer;
  end;

  PARAMREC = record
    LENGTH1: double;
    RADIUS1: double;
    EPSILON: double;
    AREA1: double;
    Q_PTS: Integer;
    QUADS: Integer;
    DIST: double;
    N_PTS: Integer;
    K_PTS: Integer;
    A_PTS: Integer;
    B_PTS: Integer;
    C_PTS: Integer;
    D_PTS: Integer;
    E_PTS: Integer;
    F_PTS: Integer;
    G_PTS: Integer;
    LENGTH2: double;
    RADIUS2: double;
    AREA2: double;
  end;

var
  X: COORDINATE;
  Y: COORDINATE;
  NUMPOINTS: Integer;
  PARAMETERS: PARAMREC;
  LCM: CMATRIX;
  PUM: BMATRIX;
  CMV: VECTOR;
  FUV: VECTOR;
  LAUNCH: Boolean;

{ Body matches realcompare_reference.pas (do not change logic). }
function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function DistPair(x1, y1, x2, y2: double): double;
begin
  DistPair := Hypot(x1 - x2, y1 - y2);
end;

{ Smallest circle radius enclosing three planar points (circumcircle or diameter of longest side). }
function MinCircleRadius3(x1, y1, x2, y2, x3, y3: double): double;
var
  d12, d23, d13: double;
  cross, area2: double;
  dotA, dotB, dotC: double;
begin
  d12 := DistPair(x1, y1, x2, y2);
  d23 := DistPair(x2, y2, x3, y3);
  d13 := DistPair(x1, y1, x3, y3);
  cross := (x2 - x1) * (y3 - y1) - (y2 - y1) * (x3 - x1);
  area2 := Abs(cross);

  if REALCOMPARE(area2, 0) = EQ then
  begin
    Result := d12;
    if REALCOMPARE(d23, Result) = GT then
      Result := d23;
    if REALCOMPARE(d13, Result) = GT then
      Result := d13;
    Result := Result / 2;
    Exit;
  end;

  dotA := (x2 - x1) * (x3 - x1) + (y2 - y1) * (y3 - y1);
  if REALCOMPARE(dotA, 0) <> GT then
  begin
    Result := d23 / 2;
    Exit;
  end;

  dotB := (x1 - x2) * (x3 - x2) + (y1 - y2) * (y3 - y2);
  if REALCOMPARE(dotB, 0) <> GT then
  begin
    Result := d13 / 2;
    Exit;
  end;

  dotC := (x1 - x3) * (x2 - x3) + (y1 - y3) * (y2 - y3);
  if REALCOMPARE(dotC, 0) <> GT then
  begin
    Result := d12 / 2;
    Exit;
  end;

  Result := (d12 * d23 * d13) / (2 * area2);
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: double): double;
begin
  Result := Abs((x2 - x1) * (y3 - y1) - (y2 - y1) * (x3 - x1)) / 2;
end;

{ Quadrant priority per spec: (0,0) I; (-1,0) II; (0,-1) III; (0,1) I; (1,0) I. }
function QuadrantOf(xpos, ypos: double): Integer;
begin
  if REALCOMPARE(xpos, 0) = EQ then
  begin
    if REALCOMPARE(ypos, 0) = EQ then
      Result := 1
    else if REALCOMPARE(ypos, 0) = LT then
      Result := 3
    else
      Result := 1;
  end
  else if REALCOMPARE(xpos, 0) = GT then
  begin
    if REALCOMPARE(ypos, 0) = EQ then
      Result := 1
    else if REALCOMPARE(ypos, 0) = GT then
      Result := 1
    else
      Result := 4;
  end
  else
  begin
    if REALCOMPARE(ypos, 0) = EQ then
      Result := 2
    else if REALCOMPARE(ypos, 0) = GT then
      Result := 2
    else
      Result := 3;
  end;
end;

function PointLineDist(px, py, ax, ay, bx, by: double): double;
var
  dx, dy, len, crossv: double;
begin
  dx := bx - ax;
  dy := by - ay;
  if (REALCOMPARE(dx, 0) = EQ) and (REALCOMPARE(dy, 0) = EQ) then
  begin
    Result := DistPair(px, py, ax, ay);
    Exit;
  end;
  len := Hypot(dx, dy);
  crossv := (px - ax) * dy - (py - ay) * dx;
  Result := Abs(crossv) / len;
end;

{ Angle at vertex (vx,vy) from points p1 and p2; returns false if undefined (coincident with vertex). }
function AngleAtVertex(px1, py1, vx, vy, px2, py2: double; out ang: double): Boolean;
var
  v1x, v1y, v2x, v2y, len1, len2, c: double;
begin
  Result := False;
  v1x := px1 - vx;
  v1y := py1 - vy;
  v2x := px2 - vx;
  v2y := py2 - vy;
  len1 := Hypot(v1x, v1y);
  len2 := Hypot(v2x, v2y);
  if (REALCOMPARE(len1, 0) = EQ) or (REALCOMPARE(len2, 0) = EQ) then
    Exit;
  c := (v1x * v2x + v1y * v2y) / (len1 * len2);
  if REALCOMPARE(c, 1) = GT then
    c := 1
  else if REALCOMPARE(c, -1) = LT then
    c := -1;
  ang := ArcCos(c);
  Result := True;
end;

function LIC3Met: Boolean;
var
  i: Integer;
  ang: double;
begin
  Result := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if not AngleAtVertex(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2], ang) then
      Continue;
    if (REALCOMPARE(ang, PI - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(ang, PI + PARAMETERS.EPSILON) = GT) then
    begin
      Result := True;
      Exit;
    end;
  end;
end;

function LIC10Met: Boolean;
var
  p1, p2, p3, i: Integer;
  ang: double;
begin
  Result := False;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - (PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2) do
  begin
    p1 := i;
    p2 := i + PARAMETERS.C_PTS + 1;
    p3 := i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2;
    if not AngleAtVertex(X[p1], Y[p1], X[p2], Y[p2], X[p3], Y[p3], ang) then
      Continue;
    if (REALCOMPARE(ang, PI - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(ang, PI + PARAMETERS.EPSILON) = GT) then
    begin
      Result := True;
      Exit;
    end;
  end;
end;

procedure DECIDE;
var
  i, j, k: Integer;
  gap1, gap2: Integer;
  ok: Boolean;
  d, r, area: double;
  qWin: array[1..4] of Boolean;
  nq, s, ee: Integer;
  qn: Integer;
  allTrue: Boolean;
  p1, p2, p3: Integer;
  hasGT, hasLT, hasBig, hasSmall: Boolean;
begin
  { --- CMV --- }

  { LIC 1 }
  CMV[1] := False;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := DistPair(X[i], Y[i], X[i + 1], Y[i + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := True;
      Break;
    end;
  end;

  { LIC 2 }
  CMV[2] := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    r := MinCircleRadius3(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
    begin
      CMV[2] := True;
      Break;
    end;
  end;

  CMV[3] := LIC3Met;

  { LIC 4 }
  CMV[4] := False;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[4] := True;
      Break;
    end;
  end;

  { LIC 5 }
  CMV[5] := False;
  for s := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for k := 1 to 4 do
      qWin[k] := False;
    for ee := 0 to PARAMETERS.Q_PTS - 1 do
    begin
      qn := QuadrantOf(X[s + ee], Y[s + ee]);
      qWin[qn] := True;
    end;
    nq := 0;
    for k := 1 to 4 do
      if qWin[k] then
        Inc(nq);
    if nq > PARAMETERS.QUADS then
    begin
      CMV[5] := True;
      Break;
    end;
  end;

  { LIC 6 }
  CMV[6] := False;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i + 1] - X[i], 0) = LT then
    begin
      CMV[6] := True;
      Break;
    end;
  end;

  { LIC 7 }
  CMV[7] := False;
  if NUMPOINTS >= 3 then
  begin
    for s := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      ee := s + PARAMETERS.N_PTS - 1;
      ok := False;
      if (REALCOMPARE(X[s], X[ee]) = EQ) and (REALCOMPARE(Y[s], Y[ee]) = EQ) then
      begin
        for k := s to ee do
        begin
          d := DistPair(X[k], Y[k], X[s], Y[s]);
          if REALCOMPARE(d, PARAMETERS.DIST) = GT then
          begin
            ok := True;
            Break;
          end;
        end;
      end
      else
      begin
        for k := s + 1 to ee - 1 do
        begin
          d := PointLineDist(X[k], Y[k], X[s], Y[s], X[ee], Y[ee]);
          if REALCOMPARE(d, PARAMETERS.DIST) = GT then
          begin
            ok := True;
            Break;
          end;
        end;
      end;
      if ok then
      begin
        CMV[7] := True;
        Break;
      end;
    end;
  end;

  { LIC 8 }
  CMV[8] := False;
  if NUMPOINTS >= 3 then
  begin
    gap1 := PARAMETERS.K_PTS + 1;
    for i := 1 to NUMPOINTS - gap1 do
    begin
      j := i + gap1;
      d := DistPair(X[i], Y[i], X[j], Y[j]);
      if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
      begin
        CMV[8] := True;
        Break;
      end;
    end;
  end;

  { LIC 9 }
  CMV[9] := False;
  if NUMPOINTS >= 5 then
  begin
    gap2 := PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2;
    for i := 1 to NUMPOINTS - gap2 do
    begin
      p1 := i;
      p2 := i + PARAMETERS.A_PTS + 1;
      p3 := i + gap2;
      r := MinCircleRadius3(X[p1], Y[p1], X[p2], Y[p2], X[p3], Y[p3]);
      if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
      begin
        CMV[9] := True;
        Break;
      end;
    end;
  end;

  CMV[10] := LIC10Met;

  { LIC 11 }
  CMV[11] := False;
  if NUMPOINTS >= 5 then
  begin
    gap2 := PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2;
    for i := 1 to NUMPOINTS - gap2 do
    begin
      p1 := i;
      p2 := i + PARAMETERS.E_PTS + 1;
      p3 := i + gap2;
      area := TriangleArea(X[p1], Y[p1], X[p2], Y[p2], X[p3], Y[p3]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      begin
        CMV[11] := True;
        Break;
      end;
    end;
  end;

  { LIC 12 }
  CMV[12] := False;
  if NUMPOINTS >= 3 then
  begin
    gap1 := PARAMETERS.G_PTS + 1;
    for i := 1 to NUMPOINTS - gap1 do
    begin
      j := i + gap1;
      if REALCOMPARE(X[j] - X[i], 0) = LT then
      begin
        CMV[12] := True;
        Break;
      end;
    end;
  end;

  { LIC 13 }
  CMV[13] := False;
  if NUMPOINTS >= 3 then
  begin
    gap1 := PARAMETERS.K_PTS + 1;
    hasGT := False;
    hasLT := False;
    for i := 1 to NUMPOINTS - gap1 do
    begin
      j := i + gap1;
      d := DistPair(X[i], Y[i], X[j], Y[j]);
      if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
        hasGT := True;
      if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then
        hasLT := True;
      if hasGT and hasLT then
        Break;
    end;
    CMV[13] := hasGT and hasLT;
  end;

  { LIC 14 }
  CMV[14] := False;
  if NUMPOINTS >= 5 then
  begin
    gap2 := PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2;
    hasBig := False;
    hasSmall := False;
    for i := 1 to NUMPOINTS - gap2 do
    begin
      p1 := i;
      p2 := i + PARAMETERS.A_PTS + 1;
      p3 := i + gap2;
      r := MinCircleRadius3(X[p1], Y[p1], X[p2], Y[p2], X[p3], Y[p3]);
      if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then
        hasBig := True;
      if (REALCOMPARE(r, PARAMETERS.RADIUS2) = LT) or (REALCOMPARE(r, PARAMETERS.RADIUS2) = EQ) then
        hasSmall := True;
      if hasBig and hasSmall then
        Break;
    end;
    CMV[14] := hasBig and hasSmall;
  end;

  { LIC 15 }
  CMV[15] := False;
  if NUMPOINTS >= 5 then
  begin
    gap2 := PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2;
    hasGT := False;
    hasLT := False;
    for i := 1 to NUMPOINTS - gap2 do
    begin
      p1 := i;
      p2 := i + PARAMETERS.E_PTS + 1;
      p3 := i + gap2;
      area := TriangleArea(X[p1], Y[p1], X[p2], Y[p2], X[p3], Y[p3]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
        hasGT := True;
      if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
        hasLT := True;
      if hasGT and hasLT then
        Break;
    end;
    CMV[15] := hasGT and hasLT;
  end;

  { --- PUM off-diagonal from LCM + CMV (diagonal already set from input) --- }
  for i := 1 to 15 do
    for j := 1 to 15 do
    begin
      if i = j then
        Continue;
      case LCM[i, j] of
        NOTUSED:
          PUM[i, j] := True;
        ANDD:
          PUM[i, j] := CMV[i] and CMV[j];
        ORR:
          PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;

  { --- FUV --- }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := True
    else
    begin
      allTrue := True;
      for j := 1 to 15 do
        if not PUM[i, j] then
        begin
          allTrue := False;
          Break;
        end;
      FUV[i] := allTrue;
    end;
  end;

  { --- LAUNCH --- }
  LAUNCH := True;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      LAUNCH := False;
      Break;
    end;
end;

function ParseConnector(const s: string): CONNECTORS;
begin
  if s = 'NOTUSED' then
    Result := NOTUSED
  else if s = 'ORR' then
    Result := ORR
  else
    Result := ANDD;
end;

procedure JsSkip(var j: TJLex);
begin
  while (j.p <= Length(j.t)) and (j.t[j.p] in [#9, #10, #13, ' ']) do
    Inc(j.p);
end;

procedure JsExpect(var j: TJLex; c: Char);
begin
  JsSkip(j);
  if (j.p > Length(j.t)) or (j.t[j.p] <> c) then
    Halt(1);
  Inc(j.p);
end;

function JsParseString(var j: TJLex): string;
begin
  Result := '';
  JsExpect(j, '"');
  while j.p <= Length(j.t) do
  begin
    if j.t[j.p] = '\' then
    begin
      Inc(j.p);
      if j.p > Length(j.t) then
        Break;
      case j.t[j.p] of
        '"', '\', '/':
          Result := Result + j.t[j.p];
        'n':
          Result := Result + #10;
        'r':
          Result := Result + #13;
        't':
          Result := Result + #9;
        else
          Result := Result + j.t[j.p];
      end;
      Inc(j.p);
    end
    else if j.t[j.p] = '"' then
    begin
      Inc(j.p);
      Exit;
    end
    else
    begin
      Result := Result + j.t[j.p];
      Inc(j.p);
    end;
  end;
end;

function JsParseNumber(var j: TJLex): double;
var
  st, code: Integer;
begin
  JsSkip(j);
  st := j.p;
  if (j.p <= Length(j.t)) and (j.t[j.p] = '-') then
    Inc(j.p);
  while j.p <= Length(j.t) do
  begin
    case j.t[j.p] of
      '0'..'9', '.', 'e', 'E', '+', '-':
        Inc(j.p);
      else
        Break;
    end;
  end;
  Val(Copy(j.t, st, j.p - st), Result, code);
  if code <> 0 then
    Halt(1);
end;

function JsParseInt(var j: TJLex): Integer;
begin
  Result := Trunc(JsParseNumber(j));
end;

procedure JsSkipValue(var j: TJLex); forward;

function JsParseBool(var j: TJLex): Boolean;
begin
  JsSkip(j);
  if Copy(j.t, j.p, 4) = 'true' then
  begin
    Result := True;
    Inc(j.p, 4);
  end
  else if Copy(j.t, j.p, 5) = 'false' then
  begin
    Result := False;
    Inc(j.p, 5);
  end
  else
    Halt(1);
end;

procedure JsParseParamObject(var j: TJLex);
var
  key: string;
begin
  JsExpect(j, '{');
  while True do
  begin
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = '}') then
    begin
      Inc(j.p);
      Break;
    end;
    key := JsParseString(j);
    JsExpect(j, ':');
    if key = 'LENGTH1' then
      PARAMETERS.LENGTH1 := JsParseNumber(j)
    else if key = 'RADIUS1' then
      PARAMETERS.RADIUS1 := JsParseNumber(j)
    else if key = 'EPSILON' then
      PARAMETERS.EPSILON := JsParseNumber(j)
    else if key = 'AREA1' then
      PARAMETERS.AREA1 := JsParseNumber(j)
    else if key = 'Q_PTS' then
      PARAMETERS.Q_PTS := JsParseInt(j)
    else if key = 'QUADS' then
      PARAMETERS.QUADS := JsParseInt(j)
    else if key = 'DIST' then
      PARAMETERS.DIST := JsParseNumber(j)
    else if key = 'N_PTS' then
      PARAMETERS.N_PTS := JsParseInt(j)
    else if key = 'K_PTS' then
      PARAMETERS.K_PTS := JsParseInt(j)
    else if key = 'A_PTS' then
      PARAMETERS.A_PTS := JsParseInt(j)
    else if key = 'B_PTS' then
      PARAMETERS.B_PTS := JsParseInt(j)
    else if key = 'C_PTS' then
      PARAMETERS.C_PTS := JsParseInt(j)
    else if key = 'D_PTS' then
      PARAMETERS.D_PTS := JsParseInt(j)
    else if key = 'E_PTS' then
      PARAMETERS.E_PTS := JsParseInt(j)
    else if key = 'F_PTS' then
      PARAMETERS.F_PTS := JsParseInt(j)
    else if key = 'G_PTS' then
      PARAMETERS.G_PTS := JsParseInt(j)
    else if key = 'LENGTH2' then
      PARAMETERS.LENGTH2 := JsParseNumber(j)
    else if key = 'RADIUS2' then
      PARAMETERS.RADIUS2 := JsParseNumber(j)
    else if key = 'AREA2' then
      PARAMETERS.AREA2 := JsParseNumber(j)
    else
      JsSkipValue(j);
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = '}') then
    begin
      Inc(j.p);
      Break;
    end;
    JsExpect(j, ',');
  end;
end;

procedure JsSkipObject(var j: TJLex);
begin
  JsExpect(j, '{');
  while True do
  begin
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = '}') then
    begin
      Inc(j.p);
      Break;
    end;
    JsParseString(j);
    JsExpect(j, ':');
    JsSkipValue(j);
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = '}') then
    begin
      Inc(j.p);
      Break;
    end;
    JsExpect(j, ',');
  end;
end;

procedure JsSkipArray(var j: TJLex);
begin
  JsExpect(j, '[');
  while True do
  begin
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = ']') then
    begin
      Inc(j.p);
      Break;
    end;
    JsSkipValue(j);
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = ']') then
    begin
      Inc(j.p);
      Break;
    end;
    JsExpect(j, ',');
  end;
end;

procedure JsSkipValue(var j: TJLex);
begin
  JsSkip(j);
  if j.p > Length(j.t) then
    Exit;
  case j.t[j.p] of
    '"':
      JsParseString(j);
    '{':
      JsSkipObject(j);
    '[':
      JsSkipArray(j);
    't', 'f':
      JsParseBool(j);
    'n':
      begin
        if Copy(j.t, j.p, 4) = 'null' then
          Inc(j.p, 4);
      end;
    else
      JsParseNumber(j);
  end;
end;

procedure JsParseDoubleCoordArray(var j: TJLex; coord: Integer);
var
  idx: Integer;
  first: Boolean;
begin
  JsExpect(j, '[');
  idx := 0;
  first := True;
  while True do
  begin
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = ']') then
    begin
      Inc(j.p);
      Break;
    end;
    if not first then
      JsExpect(j, ',');
    first := False;
    Inc(idx);
    if idx > 100 then
      Halt(1);
    if coord = 1 then
      X[idx] := JsParseNumber(j)
    else
      Y[idx] := JsParseNumber(j);
  end;
  if coord = 1 then
    NUMPOINTS := idx;
end;

procedure JsParseLcm(var j: TJLex);
var
  ri, ci: Integer;
  firstRow, firstCell: Boolean;
  cell: string;
begin
  JsExpect(j, '[');
  firstRow := True;
  ri := 0;
  while True do
  begin
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = ']') then
    begin
      Inc(j.p);
      Break;
    end;
    if not firstRow then
      JsExpect(j, ',');
    firstRow := False;
    Inc(ri);
    JsExpect(j, '[');
    firstCell := True;
    ci := 0;
    while True do
    begin
      JsSkip(j);
      if (j.p <= Length(j.t)) and (j.t[j.p] = ']') then
      begin
        Inc(j.p);
        Break;
      end;
      if not firstCell then
        JsExpect(j, ',');
      firstCell := False;
      Inc(ci);
      cell := JsParseString(j);
      LCM[ri, ci] := ParseConnector(cell);
    end;
    if ci <> 15 then
      Halt(1);
  end;
  if ri <> 15 then
    Halt(1);
end;

procedure JsParsePumDiag(var j: TJLex);
var
  ii: Integer;
  first: Boolean;
begin
  JsExpect(j, '[');
  ii := 0;
  first := True;
  while True do
  begin
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = ']') then
    begin
      Inc(j.p);
      Break;
    end;
    if not first then
      JsExpect(j, ',');
    first := False;
    Inc(ii);
    PUM[ii, ii] := JsParseBool(j);
  end;
  if ii <> 15 then
    Halt(1);
end;

procedure JsParseRoot(var j: TJLex);
var
  key: string;
begin
  JsExpect(j, '{');
  while True do
  begin
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = '}') then
    begin
      Inc(j.p);
      Break;
    end;
    key := JsParseString(j);
    JsExpect(j, ':');
    if key = 'numpoints' then
      NUMPOINTS := JsParseInt(j)
    else if key = 'x' then
      JsParseDoubleCoordArray(j, 1)
    else if key = 'y' then
      JsParseDoubleCoordArray(j, 2)
    else if key = 'parameters' then
      JsParseParamObject(j)
    else if key = 'lcm' then
      JsParseLcm(j)
    else if key = 'pum_diag' then
      JsParsePumDiag(j)
    else
      JsSkipValue(j);
    JsSkip(j);
    if (j.p <= Length(j.t)) and (j.t[j.p] = '}') then
    begin
      Inc(j.p);
      Break;
    end;
    JsExpect(j, ',');
  end;
end;

function BuildOutputJSON: string;
var
  i, jj: Integer;
  sb: string;
begin
  sb := '{"cmv":[';
  for i := 1 to 15 do
  begin
    if i > 1 then
      sb := sb + ',';
    if CMV[i] then
      sb := sb + 'true'
    else
      sb := sb + 'false';
  end;
  sb := sb + '],"pum":[';
  for i := 1 to 15 do
  begin
    if i > 1 then
      sb := sb + ',';
    sb := sb + '[';
    for jj := 1 to 15 do
    begin
      if jj > 1 then
        sb := sb + ',';
      if PUM[i, jj] then
        sb := sb + 'true'
      else
        sb := sb + 'false';
    end;
    sb := sb + ']';
  end;
  sb := sb + '],"fuv":[';
  for i := 1 to 15 do
  begin
    if i > 1 then
      sb := sb + ',';
    if FUV[i] then
      sb := sb + 'true'
    else
      sb := sb + 'false';
  end;
  sb := sb + '],"launch":';
  if LAUNCH then
    sb := sb + 'true}'
  else
    sb := sb + 'false}';
  Result := sb;
end;

function ReadAllStdin: string;
var
  ms: TMemoryStream;
  h: THandleStream;
  n: LongInt;
  buf: array[0..16383] of Byte;
begin
  ms := TMemoryStream.Create;
  h := THandleStream.Create(StdInputHandle);
  try
    repeat
      n := h.Read(buf, SizeOf(buf));
      if n > 0 then
        ms.Write(buf, n);
    until n = 0;
    SetLength(Result, ms.Size);
    if ms.Size > 0 then
      Move(ms.Memory^, Result[1], ms.Size);
  finally
    h.Free;
    ms.Free;
  end;
end;

var
  lex: TJLex;
  stdinData: string;
begin
  stdinData := ReadAllStdin;
  if (Length(stdinData) >= 3) and (stdinData[1] = #$EF) and (stdinData[2] = #$BB) and
    (stdinData[3] = #$BF) then
    Delete(stdinData, 1, 3);
  lex.t := stdinData;
  lex.p := 1;
  JsParseRoot(lex);
  JsSkip(lex);
  if lex.p <= Length(lex.t) then
    ; { trailing junk ignored }
  DECIDE;
  WriteLn(BuildOutputJSON);
end.
